export const UNIFORMS_SIZE_BYTES = 64
export const UNIFORMS_SIZE_F32 = 16

// Byte offsets (into an ArrayBuffer / DataView).
export const UNIFORM_OFFSET_BYTES = {
  bpRangeX: 0,
  regionStart: 12,
  canvasHeight: 16,
  scaleType: 20,
  renderingType: 24,
  numRows: 28,
  domainYMin: 32,
  domainYMax: 36,
  zero: 40,
  viewportWidth: 44,
  reversed: 48,
} as const

// Indices into a Float32Array / Uint32Array view.
export const UNIFORM_OFFSET_F32 = {
  bpRangeX: 0,
  regionStart: 3,
  canvasHeight: 4,
  scaleType: 5,
  renderingType: 6,
  numRows: 7,
  domainYMin: 8,
  domainYMax: 9,
  zero: 10,
  viewportWidth: 11,
  reversed: 12,
} as const

export interface Uniforms {
  bpRangeX: [number, number, number]
  regionStart: number
  canvasHeight: number
  scaleType: number
  renderingType: number
  numRows: number
  domainYMin: number
  domainYMax: number
  zero: number
  viewportWidth: number
  reversed: number
}

export function writeUniforms(buf: ArrayBuffer, uniforms: Uniforms) {
  const f32 = new Float32Array(buf)
  const u32 = new Uint32Array(buf)
  const i32 = new Int32Array(buf)
  f32[0] = uniforms.bpRangeX[0]
  f32[1] = uniforms.bpRangeX[1]
  f32[2] = uniforms.bpRangeX[2]
  u32[3] = uniforms.regionStart
  f32[4] = uniforms.canvasHeight
  i32[5] = uniforms.scaleType
  i32[6] = uniforms.renderingType
  f32[7] = uniforms.numRows
  f32[8] = uniforms.domainYMin
  f32[9] = uniforms.domainYMax
  f32[10] = uniforms.zero
  f32[11] = uniforms.viewportWidth
  f32[12] = uniforms.reversed
}

export const INSTANCE_STRIDE_BYTES = 24
export const INSTANCE_STRIDE_F32 = 6

export const FIELD_OFFSET_BYTES = {
  startEnd: 0,
  score: 8,
  prevScore: 12,
  color: 16,
  rowIndex: 20,
} as const

export const FIELD_OFFSET_F32 = {
  startEnd: 0,
  score: 2,
  prevScore: 3,
  color: 4,
  rowIndex: 5,
} as const

export const GL_ATTRIBUTES: readonly GlAttributeLayout[] = [
  { name: 'a_startEnd', components: 2, type: 'uint', offsetBytes: 0, integer: true },
  { name: 'a_score', components: 1, type: 'float', offsetBytes: 8, integer: false },
  { name: 'a_prevScore', components: 1, type: 'float', offsetBytes: 12, integer: false },
  { name: 'a_color', components: 1, type: 'uint', offsetBytes: 16, integer: true },
  { name: 'a_rowIndex', components: 1, type: 'float', offsetBytes: 20, integer: false },
]

export interface WiggleInstance {
  startEnd: [number, number]
  score: number
  prevScore: number
  color: number
  rowIndex: number
}

export function writeWiggleInstance(buf: ArrayBuffer, instanceIndex: number, inst: WiggleInstance) {
  const base = instanceIndex * 24
  const dv = new DataView(buf)
  dv.setUint32(base + 0, inst.startEnd[0], true)
  dv.setUint32(base + 4, inst.startEnd[1], true)
  dv.setFloat32(base + 8, inst.score, true)
  dv.setFloat32(base + 12, inst.prevScore, true)
  dv.setUint32(base + 16, inst.color, true)
  dv.setFloat32(base + 20, inst.rowIndex, true)
}
